VALUES
  ('elementary-0489de64-moex-00631', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '以下關於大眾運輸轉運站規劃之敘述何者錯誤？', '["所需用地涉及都市計畫變更者，主管機關應協調都市計畫主管機關依規定辦理變更", "涉及非都市土地使用變更者，主管機關應協調區域計畫主管機關依規定辦理變更", "主管機關對於大眾運輸場站或轉運站之土地及建築物，得協調相關主管機關調整其使用項目或使用強度", "轉運站得依交通區位條件設於國土計畫之農業發展區"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00632', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列關於發展大眾運輸條例之敘述何者錯誤？', '["主管機關於運輸營運者所服務之路線、航線或區域內，均應規劃提供無障礙運輸服務，及規劃設置無 障礙設施與設備", "主管機關為改善大眾運輸營運環境，得規劃、設計、興建及營運道路之優先及專用制度", "為提升大眾運輸服務品質，主管機關應輔導獎助大眾運輸系統間之票證、轉運、行旅資訊及相關運輸 服務之整合", "主管機關應定期辦理大眾運輸之營運評鑑，其評鑑及獎勵基準等事項之辦法，由各地方主管機關訂定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00633', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '以下那一項交通建設最初採用BOT招標，但最後並未採用BOT方式興建？', '["桃園機場捷運", "高雄捷運", "臺北轉運站", "高速公路ETC"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00634', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列那一項大眾運輸票價，係依法律規定，而予以優待？', '["回數票", "兒童票", "早鳥票", "團體票"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00635', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '超速違規之舉發，採用固定或非固定式科學儀器取得證據資料證明者，下列敘述何者正確？', '["於高速公路應於二百公尺至五百公尺間，明顯標示之", "於一般道路應於一百公尺至三百公尺間，明顯標示之", "於快速公路應於一百公尺至三百公尺間，明顯標示之", "定點當場攔截製單舉發者，應於二百公尺至五百公尺間，明顯標示之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00636', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '為維護道路交通安全與暢通，公路或警察機關於必要時，得發布命令之事項不包括下列那一項？', '["開徵道路擁擠費", "指定某線道路或某線道路區段禁止或限制車輛、行人通行", "劃定行人徒步區", "禁止穿越道路，或禁止停車及臨時停車"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00637', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '如果貨輪在商港區域外擱淺，船舶之船長及船舶所有人未履行移除前，航港局得優先進行下列那項措施？', '["要求船舶所有人提供相當額度之財務擔保。未提供擔保前，航港局得限制相關船員離境", "打國際仲裁官司確認賠償金額", "向承攬船舶保險之公司申請理賠", "拍賣船舶及運載貨物作為賠償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00638', 'elementary-0489de64', 'elementary-0489de64-moex-111-b3f42868', 'sub-elementary-0489de64-02', NULL, 'single_choice', '以下何種權利屬於智慧財產權？', '["債權", "抵押權", "商標權", "姓名權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00639', 'elementary-0489de64', 'elementary-0489de64-moex-111-b3f42868', 'sub-elementary-0489de64-02', NULL, 'single_choice', '甲基金會自創辦以來，致力於雛妓救援與家暴受害者庇護，近年尤努力消彌社會中所有性/性別暴力行為 與壓迫，以建立性別公義的社會。有關甲基金會的敘述，下列何者正確？', '["和政黨一樣都是屬於非營利組織", "從民法的屬性分類屬於社團法人", "關心社會議題的層面較政黨多元", "常藉由政治參選達成該組織宗旨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00640', 'elementary-0489de64', 'elementary-0489de64-moex-111-b3f42868', 'sub-elementary-0489de64-02', NULL, 'single_choice', '柔柔生長在一個小康的家庭，父母親從小就栽培她學習各項才藝，塑造了柔柔高雅的氣質和談吐。上述 現象最適合用下列那一種概念加以說明？', '["經濟資本", "社會資本", "象徵資本", "文化資本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
